#include<bits/stdc++.h>
using namespace std;
int a[10000];
int main()
{
	int n,k;
	cin>>n>>k;
	for(int i=1;i<=n;i++){
		cin>>a[i];
	}
	sort(a+1,a+n+1);
	int sum=0,l=1,r=1,maxi=0;
	while(r<=n){
		if(a[r]-a[l]<=k){
			sum+=a[r];
			r++;
		}else{
			sum-=a[l];
			l++;
		}
	//	cout<<l<<" "<<r<<endl;
		maxi=max(sum,maxi);
	}
	cout<<maxi;
}
